namespace sv_a7f0b1c8737244c08937ca635b7f9f1c.Models;

public record JobApplication(PersonalInfo Personal, WorkHistory Work, List<Reference> References, string CoverLetter);
public record PersonalInfo(string FullName, string Email, string Phone, string Address);
public record WorkHistory(List<WorkEntry> Entries);
public record WorkEntry(string Company, string Title, DateTime StartDate, DateTime? EndDate, string Description);
public record Reference(string Name, string Relationship, string Email, string Phone);

public interface IApplicationService
{
    Task<int> SubmitApplicationAsync(JobApplication application);
    Task<bool> ValidateEmailAsync(string email);
}

@* Step progress indicator bar *@

<nav aria-label="Application steps">
    <ol class="step-indicator d-flex list-unstyled mb-4 p-0">
        @for (int i = 0; i < StepNames.Count; i++)
        {
            var stepIndex = i;
            var isCompleted = CompletedSteps.Contains(stepIndex);
            var isCurrent = stepIndex == CurrentStep;
            var isFuture = !isCompleted && !isCurrent;

            <li class="step-item flex-fill text-center @(isCurrent ? "active" : "") @(isCompleted ? "completed" : "") @(isFuture ? "future" : "")"
                @onclick="() => HandleStepClick(stepIndex)"
                role="button"
                style="cursor: @(isCompleted ? "pointer" : "default")">
                <div class="step-circle mx-auto mb-1 d-flex align-items-center justify-content-center rounded-circle
                            @(isCurrent ? "bg-primary text-white" : isCompleted ? "bg-success text-white" : "bg-light text-muted border")"
                     style="width: 36px; height: 36px; font-size: 0.85rem;">
                    @if (isCompleted)
                    {
                        <span>&#10003;</span>
                    }
                    else
                    {
                        <span>@(stepIndex + 1)</span>
                    }
                </div>
                <small class="@(isFuture ? "text-muted" : "")">@StepNames[stepIndex]</small>
            </li>
        }
    </ol>
</nav>

@code {
    [Parameter, EditorRequired] public int CurrentStep { get; set; }
    [Parameter, EditorRequired] public HashSet<int> CompletedSteps { get; set; } = new();
    [Parameter, EditorRequired] public EventCallback<int> OnStepClicked { get; set; }

    private static readonly List<string> StepNames = new()
    {
        "Personal Info", "Work History", "References", "Cover Letter", "Review & Submit"
    };

    private async Task HandleStepClick(int step)
    {
        if (CompletedSteps.Contains(step))
        {
            await OnStepClicked.InvokeAsync(step);
        }
    }
}

@* Single work history entry form *@

<div class="card mb-3">
    <div class="card-body">
        <div class="d-flex justify-content-between align-items-center mb-3">
            <h6 class="card-title mb-0">Position @(Index + 1)</h6>
            @if (CanRemove)
            {
                <button type="button" class="btn btn-outline-danger btn-sm" @onclick="OnRemove">Remove</button>
            }
        </div>

        <div class="row g-3">
            <div class="col-md-6">
                <label class="form-label">Company Name <span class="text-danger">*</span></label>
                <input type="text" class="form-control" value="@Entry.Company"
                       @onchange="e => Update(Entry with { Company = (string?)e.Value ?? string.Empty })" />
            </div>
            <div class="col-md-6">
                <label class="form-label">Job Title <span class="text-danger">*</span></label>
                <input type="text" class="form-control" value="@Entry.Title"
                       @onchange="e => Update(Entry with { Title = (string?)e.Value ?? string.Empty })" />
            </div>
            <div class="col-md-4">
                <label class="form-label">Start Date <span class="text-danger">*</span></label>
                <input type="date" class="form-control" value="@FormatDate(Entry.StartDate)"
                       @onchange="e => Update(Entry with { StartDate = ParseDate((string?)e.Value) })" />
            </div>
            <div class="col-md-4">
                <label class="form-label">End Date</label>
                <input type="date" class="form-control" value="@FormatDate(Entry.EndDate)"
                       disabled="@IsCurrent"
                       @onchange="e => Update(Entry with { EndDate = ParseNullableDate((string?)e.Value) })" />
            </div>
            <div class="col-md-4 d-flex align-items-end">
                <div class="form-check mb-2">
                    <input type="checkbox" class="form-check-input" id="current-@Index" checked="@IsCurrent"
                           @onchange="e => ToggleCurrent((bool?)e.Value ?? false)" />
                    <label class="form-check-label" for="current-@Index">Currently working here</label>
                </div>
            </div>
            <div class="col-12">
                <label class="form-label">Description</label>
                <textarea class="form-control" rows="3" value="@Entry.Description"
                          @onchange="e => Update(Entry with { Description = (string?)e.Value ?? string.Empty })"></textarea>
            </div>
        </div>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public WorkEntry Entry { get; set; } = default!;
    [Parameter] public int Index { get; set; }
    [Parameter] public bool CanRemove { get; set; }
    [Parameter] public EventCallback<WorkEntry> OnEntryChanged { get; set; }
    [Parameter] public EventCallback OnRemove { get; set; }

    private bool IsCurrent => Entry.EndDate is null && Entry.StartDate != default;

    private async Task Update(WorkEntry updated) => await OnEntryChanged.InvokeAsync(updated);

    private void ToggleCurrent(bool isCurrent)
    {
        var updated = isCurrent
            ? Entry with { EndDate = null }
            : Entry with { EndDate = DateTime.Today };
        _ = OnEntryChanged.InvokeAsync(updated);
    }

    private static string FormatDate(DateTime date) => date == default ? "" : date.ToString("yyyy-MM-dd");
    private static string FormatDate(DateTime? date) => date?.ToString("yyyy-MM-dd") ?? "";
    private static DateTime ParseDate(string? value) => DateTime.TryParse(value, out var d) ? d : default;
    private static DateTime? ParseNullableDate(string? value) => DateTime.TryParse(value, out var d) ? d : null;
}

