@* Step 1 — Personal Information *@
@using sv_a7f0b1c8737244c08937ca635b7f9f1c.Models

<h4 class="mb-3">Personal Information</h4>

@if (!string.IsNullOrEmpty(ErrorMessage))
{
    <div class="alert alert-danger">@ErrorMessage</div>
}

<div class="row g-3">
    <div class="col-md-6">
        <label class="form-label">Full Name <span class="text-danger">*</span></label>
        <input type="text" class="form-control" value="@FullName"
               @onchange="e => FullName = (string?)e.Value ?? string.Empty" />
    </div>
    <div class="col-md-6">
        <label class="form-label">Email <span class="text-danger">*</span></label>
        <input type="email" class="form-control" value="@Email"
               @onchange="e => Email = (string?)e.Value ?? string.Empty" />
    </div>
    <div class="col-md-6">
        <label class="form-label">Phone <span class="text-danger">*</span></label>
        <input type="tel" class="form-control" value="@Phone"
               @onchange="e => Phone = (string?)e.Value ?? string.Empty" />
    </div>
    <div class="col-md-6">
        <label class="form-label">Address <span class="text-danger">*</span></label>
        <input type="text" class="form-control" value="@Address"
               @onchange="e => Address = (string?)e.Value ?? string.Empty" />
    </div>
</div>

<div class="d-flex justify-content-end mt-4">
    <button class="btn btn-primary" @onclick="HandleNext" disabled="@IsValidating">
        @if (IsValidating)
        {
            <span class="spinner-border spinner-border-sm me-1" role="status"></span>
        }
        Next
    </button>
</div>

@code {
    [Parameter] public PersonalInfo? Info { get; set; }
    [Parameter, EditorRequired] public EventCallback<PersonalInfo> OnNext { get; set; }
    [Parameter, EditorRequired] public IApplicationService ApplicationService { get; set; } = default!;

    private string FullName = "";
    private string Email = "";
    private string Phone = "";
    private string Address = "";
    private string? ErrorMessage;
    private bool IsValidating;

    protected override void OnParametersSet()
    {
        if (Info is not null)
        {
            FullName = Info.FullName;
            Email = Info.Email;
            Phone = Info.Phone;
            Address = Info.Address;
        }
    }

    private async Task HandleNext()
    {
        ErrorMessage = null;

        if (string.IsNullOrWhiteSpace(FullName) || string.IsNullOrWhiteSpace(Email)
            || string.IsNullOrWhiteSpace(Phone) || string.IsNullOrWhiteSpace(Address))
        {
            ErrorMessage = "All fields are required.";
            return;
        }

        IsValidating = true;
        try
        {
            var emailValid = await ApplicationService.ValidateEmailAsync(Email.Trim());
            if (!emailValid)
            {
                ErrorMessage = "The email address is not valid.";
                return;
            }

            await OnNext.InvokeAsync(new PersonalInfo(FullName.Trim(), Email.Trim(), Phone.Trim(), Address.Trim()));
        }
        finally
        {
            IsValidating = false;
        }
    }
}

@* Step 2 — Work History *@
@using sv_a7f0b1c8737244c08937ca635b7f9f1c.Models

<h4 class="mb-3">Work History</h4>

@if (!string.IsNullOrEmpty(ErrorMessage))
{
    <div class="alert alert-danger">@ErrorMessage</div>
}

@for (int i = 0; i < Entries.Count; i++)
{
    var index = i;
    <WorkEntryForm Entry="@Entries[index]"
                   Index="index"
                   CanRemove="@(Entries.Count > 1)"
                   OnEntryChanged="entry => UpdateEntry(index, entry)"
                   OnRemove="() => RemoveEntry(index)" />
}

<button type="button" class="btn btn-outline-secondary mb-3" @onclick="AddEntry">
    + Add Another Position
