@* Step 2 — Work History *@
@using sv_a7f0b1c8737244c08937ca635b7f9f1c.Models

<h4 class="mb-3">Work History</h4>

@if (!string.IsNullOrEmpty(ErrorMessage))
{
    <div class="alert alert-danger">@ErrorMessage</div>
}

@for (int i = 0; i < Entries.Count; i++)
{
    var index = i;
    <WorkEntryForm Entry="@Entries[index]"
                   Index="index"
                   CanRemove="@(Entries.Count > 1)"
                   OnEntryChanged="entry => UpdateEntry(index, entry)"
                   OnRemove="() => RemoveEntry(index)" />
}

<button type="button" class="btn btn-outline-secondary mb-3" @onclick="AddEntry">
    + Add Another Position
</button>

<div class="d-flex justify-content-between mt-3">
    <button class="btn btn-secondary" @onclick="OnBack">Back</button>
    <button class="btn btn-primary" @onclick="HandleNext">Next</button>
</div>

@code {
    [Parameter] public List<WorkEntry>? InitialEntries { get; set; }
    [Parameter, EditorRequired] public EventCallback<List<WorkEntry>> OnNext { get; set; }
    [Parameter, EditorRequired] public EventCallback OnBack { get; set; }

    private List<WorkEntry> Entries = new();
    private string? ErrorMessage;

    protected override void OnInitialized()
    {
        if (InitialEntries is { Count: > 0 })
        {
            Entries = InitialEntries.Select(e => e).ToList();
        }
        else
        {
            Entries = new List<WorkEntry> { new("", "", default, null, "") };
        }
    }

    private void UpdateEntry(int index, WorkEntry updated)
    {
        Entries[index] = updated;
    }

    private void AddEntry()
    {
        Entries.Add(new WorkEntry("", "", default, null, ""));
    }

    private void RemoveEntry(int index)
    {
        if (Entries.Count > 1)
        {
            Entries.RemoveAt(index);
        }
    }

    private async Task HandleNext()
    {
        ErrorMessage = null;

        foreach (var entry in Entries)
        {
            if (string.IsNullOrWhiteSpace(entry.Company) || string.IsNullOrWhiteSpace(entry.Title)
                || entry.StartDate == default)
            {
                ErrorMessage = "Each position requires a company name, job title, and start date.";
                return;
            }
        }

        await OnNext.InvokeAsync(Entries.ToList());
    }
}

