@page "/apply"
@rendermode InteractiveServer
@using sv_a7f0b1c8737244c08937ca635b7f9f1c.Models
@inject IApplicationService ApplicationService

<PageTitle>Job Application</PageTitle>

<div class="container py-4" style="max-width: 800px;">
    <h2 class="mb-4">Job Application</h2>

    @if (IsSubmitted)
    {
        <div class="alert alert-success text-center py-5">
            <h3 class="mb-3">&#10003; Application Submitted!</h3>
            <p class="lead">Your application has been received.</p>
            <p><strong>Application ID: @ApplicationId</strong></p>
        </div>
    }
    else
    {
        <StepIndicator CurrentStep="@CurrentStep"
                       CompletedSteps="@CompletedSteps"
                       OnStepClicked="GoToStep" />

        @switch (CurrentStep)
        {
            case 0:
                <PersonalInfoStep Info="@PersonalInfoData"
                                  ApplicationService="@ApplicationService"
                                  OnNext="HandlePersonalInfoNext" />
                break;

            case 1:
                <WorkHistoryStep InitialEntries="@WorkEntries"
                                 OnNext="HandleWorkHistoryNext"
                                 OnBack="GoBack" />
                break;

            case 2:
                <ReferencesStep InitialReferences="@ReferencesList"
                                OnNext="HandleReferencesNext"
                                OnBack="GoBack" />
                break;

            case 3:
                <CoverLetterStep InitialText="@CoverLetterText"
                                 OnNext="HandleCoverLetterNext"
                                 OnBack="GoBack" />
                break;

            case 4:
                <ReviewStep Personal="@PersonalInfoData"
                            WorkEntries="@WorkEntries"
                            References="@ReferencesList"
                            CoverLetter="@CoverLetterText"
                            OnEditSection="GoToStep"
                            OnBack="GoBack"
                            OnSubmit="HandleSubmit" />
                break;
        }
    }
</div>

@code {
    private int CurrentStep;
    private HashSet<int> CompletedSteps = new();

    private PersonalInfo? PersonalInfoData;
    private List<WorkEntry>? WorkEntries;
    private List<Reference>? ReferencesList;
    private string CoverLetterText = "";

    private bool IsSubmitted;
    private int ApplicationId;

    private void GoToStep(int step)
    {
        CurrentStep = step;
    }

    private void GoBack()
    {
        if (CurrentStep > 0)
            CurrentStep--;
    }

    private void HandlePersonalInfoNext(PersonalInfo info)
    {
        PersonalInfoData = info;
        CompletedSteps.Add(0);
        CurrentStep = 1;
    }

    private void HandleWorkHistoryNext(List<WorkEntry> entries)
    {
        WorkEntries = entries;
        CompletedSteps.Add(1);
        CurrentStep = 2;
    }

    private void HandleReferencesNext(List<Reference> references)
    {
        ReferencesList = references;
        CompletedSteps.Add(2);
        CurrentStep = 3;
    }

    private void HandleCoverLetterNext(string coverLetter)
    {
        CoverLetterText = coverLetter;
        CompletedSteps.Add(3);
        CurrentStep = 4;
    }

    private async Task HandleSubmit()
    {
        var application = new JobApplication(
            PersonalInfoData!,
            new WorkHistory(WorkEntries!),
            ReferencesList!,
            CoverLetterText
        );

        ApplicationId = await ApplicationService.SubmitApplicationAsync(application);
        IsSubmitted = true;
    }
}

